import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axiosClient from "../../../axiosClient";
import styles from "../../../LibraryDashboard.module.css";

export default function BookAddForm() {
    const [title, setTitle] = useState("");
    const [author_id, setAuthorId] = useState("");
    const [description, setDescription] = useState("");
    const [quantity, setQuantity] = useState(0);
    const [price, setPrice] = useState(0); 
    const [image, setImage] = useState(null);
    const [category_id, setCategoryId] = useState("");
    const [authors, setAuthors] = useState([]);
    const [categories, setCategories] = useState([]);
    const [error, setError] = useState({});
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        const fetchAuthors = async () => {
            const response = await axiosClient.get('/authors');
            setAuthors(response.data);
        };

        const fetchCategories = async () => {
            const response = await axiosClient.get('/categories');
            setCategories(response.data);
        };

        fetchAuthors();
        fetchCategories();
    }, []);

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);

        const formData = new FormData();
        formData.append('title', title);
        formData.append('author_id', author_id);
        formData.append('description', description);
        formData.append('quantity', quantity);
        formData.append('price', price);
        formData.append('image', image);
        formData.append('category_id', category_id);

        try {
            const response = await axiosClient.post("/books/create", formData, {
                headers: {
                    'Content-Type': 'multipart/form-data'
                }
            });
            setError({});
            window.location.href = "/admin/dashboard/books?message=Book added successfully";
        } catch (error) {
            if (error.response && error.response.status === 422) {
                setError(error.response.data.error || {});
            } else {
                setError({ general: "An unexpected error occurred. Please try again later." });
                console.log(error);
            }
        } finally {
            setLoading(false);
        }
    };

    return (
        <form onSubmit={handleSubmit} className="max-w-2xl mx-auto bg-white p-8 rounded-xl shadow-xl">
            <header className="flex justify-between items-center mb-8">
                <h2 className="text-3xl font-bold text-gray-800">Add Book</h2>
                <Link to="/admin/dashboard/books" className="p-2 hover:bg-gray-100 rounded-full transition-colors duration-200">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-gray-600" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M10.293 2.293a1 1 0 011.414 0l8 8a1 1 0 010 1.414l-8 8a1 1 0 01-1.414-1.414L16.586 11H3a1 1 0 110-2h13.586l-6.293-6.293a1 1 0 010-1.414z" clipRule="evenodd" />
                    </svg>
                </Link>
            </header>

            <div className="space-y-6">
                {loading && (
                    <div className="text-center py-4">
                        <div className="inline-block animate-spin rounded-full h-8 w-8 border-b-2 border-[#274e79]"></div>
                        <p className="mt-2 text-gray-500">Processing...</p>
                    </div>
                )}

                {error.general && (
                    <div className="bg-red-50 border-l-4 border-red-400 p-4 rounded-md">
                        <p className="text-red-700 text-sm">{error.general}</p>
                    </div>
                )}

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="space-y-2">
                        <label htmlFor="title" className="block text-sm font-medium text-gray-700">Title</label>
                    <input
                        type="text"
                        id="title"
                        name="title"
                        value={title}
                        onChange={(e) => setTitle(e.target.value)}
                            className="w-full px-4 py-3 rounded-lg border border-gray-300 focus:ring-2 focus:ring-[#274e79] focus:border-transparent transition duration-200"
                            placeholder="Enter book title"
                    />
                        {error.title && <p className="text-red-500 text-xs mt-1">{error.title[0]}</p>}
                </div>

                    <div className="space-y-2">
                        <label htmlFor="author_id" className="block text-sm font-medium text-gray-700">Author</label>
                    <select
                        id="author_id"
                        name="author_id"
                        value={author_id}
                        onChange={(e) => setAuthorId(e.target.value)}
                            className="w-full px-4 py-3 rounded-lg border border-gray-300 focus:ring-2 focus:ring-[#274e79] focus:border-transparent transition duration-200"
                    >
                        <option value="">Select Author</option>
                            {authors.map(author => (
                            <option key={author.id} value={author.id}>{author.name}</option>
                        ))}
                    </select>
                        {error.author_id && <p className="text-red-500 text-xs mt-1">{error.author_id[0]}</p>}
                    </div>

                    <div className="space-y-2">
                        <label htmlFor="category_id" className="block text-sm font-medium text-gray-700">Category</label>
                        <select
                            id="category_id"
                            name="category_id"
                            value={category_id}
                            onChange={(e) => setCategoryId(e.target.value)}
                            className="w-full px-4 py-3 rounded-lg border border-gray-300 focus:ring-2 focus:ring-[#274e79] focus:border-transparent transition duration-200"
                        >
                            <option value="">Select Category</option>
                            {categories.map(category => (
                                <option key={category.id} value={category.id}>{category.name}</option>
                            ))}
                        </select>
                        {error.category_id && <p className="text-red-500 text-xs mt-1">{error.category_id[0]}</p>}
                    </div>

                    <div className="space-y-2">
                        <label htmlFor="quantity" className="block text-sm font-medium text-gray-700">Quantity</label>
                        <input
                            type="number"
                            id="quantity"
                            name="quantity"
                            value={quantity}
                            onChange={(e) => setQuantity(e.target.value)}
                            className="w-full px-4 py-3 rounded-lg border border-gray-300 focus:ring-2 focus:ring-[#274e79] focus:border-transparent transition duration-200"
                            placeholder="Enter quantity"
                        />
                        {error.quantity && <p className="text-red-500 text-xs mt-1">{error.quantity[0]}</p>}
                    </div>
                </div>

                <div className="space-y-2">
                    <label htmlFor="description" className="block text-sm font-medium text-gray-700">Description</label>
                    <textarea
                        id="description"
                        name="description"
                        value={description}
                        onChange={(e) => setDescription(e.target.value)}
                        rows="4"
                        className="w-full px-4 py-3 rounded-lg border border-gray-300 focus:ring-2 focus:ring-[#274e79] focus:border-transparent transition duration-200"
                        placeholder="Enter book description"
                    />
                    {error.description && <p className="text-red-500 text-xs mt-1">{error.description[0]}</p>}
                </div>

                <div className="space-y-2">
                    <label htmlFor="image" className="block text-sm font-medium text-gray-700">Book Cover</label>
                    <div className="mt-1 flex justify-center px-6 pt-5 pb-6 border-2 border-gray-300 border-dashed rounded-lg hover:border-[#274e79] transition-colors duration-200">
                        <div className="space-y-1 text-center">
                            <svg className="mx-auto h-12 w-12 text-gray-400" stroke="currentColor" fill="none" viewBox="0 0 48 48" aria-hidden="true">
                                <path d="M28 8H12a4 4 0 00-4 4v20m32-12v8m0 0v8a4 4 0 01-4 4H12a4 4 0 01-4-4v-4m32-4l-3.172-3.172a4 4 0 00-5.656 0L28 28M8 32l9.172-9.172a4 4 0 015.656 0L28 28m0 0l4 4m4-24h8m-4-4v8m-12 4h.02" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                            </svg>
                            <div className="flex text-sm text-gray-600">
                                <label htmlFor="image" className="relative cursor-pointer bg-white rounded-md font-medium text-[#274e79] hover:text-[#1a3b5c] focus-within:outline-none focus-within:ring-2 focus-within:ring-offset-2 focus-within:ring-[#274e79]">
                                    <span>Upload a file</span>
                    <input
                        id="image"
                        name="image"
                                        type="file"
                        onChange={(e) => setImage(e.target.files[0])}
                                        className="sr-only"
                                    />
                                </label>
                                <p className="pl-1">or drag and drop</p>
                            </div>
                            <p className="text-xs text-gray-500">PNG, JPG, GIF up to 10MB</p>
                        </div>
                    </div>
                    {error.image && <p className="text-red-500 text-xs mt-1">{error.image[0]}</p>}
                </div>

                <div className="flex justify-end pt-6">
                    <button
                        type="submit"
                        disabled={loading}
                        className="px-6 py-3 bg-[#274e79] text-white rounded-lg hover:bg-[#1a3b5c] focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-[#274e79] transition duration-200 flex items-center space-x-2"
                    >
                        {loading ? (
                            <>
                                <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-white"></div>
                                <span>Adding Book...</span>
                            </>
                        ) : (
                            <>
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
                                </svg>
                                <span>Add Book</span>
                            </>
                        )}
                    </button>
                </div>
            </div>
        </form>
    );
}

import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axiosClient from "../../../axiosClient";
import styles from "../../../LibraryDashboard.module.css";

export default function BookAddForm() {
    const [title, setTitle] = useState("");
    const [author_id, setAuthorId] = useState("");
    const [description, setDescription] = useState("");
    const [quantity, setQuantity] = useState(0);
    const [price, setPrice] = useState(0); 
    const [image, setImage] = useState(null);
    const [category_id, setCategoryId] = useState("");
    const [authors, setAuthors] = useState([]);
    const [categories, setCategories] = useState([]);
    const [error, setError] = useState({});
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        const fetchAuthors = async () => {
            const response = await axiosClient.get('/authors');
            setAuthors(response.data);
        };

        const fetchCategories = async () => {
            const response = await axiosClient.get('/categories');
            setCategories(response.data);
        };

        fetchAuthors();
        fetchCategories();
    }, []);

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);

        const formData = new FormData();
        formData.append('title', title);
        formData.append('author_id', author_id);
        formData.append('description', description);
        formData.append('quantity', quantity);
        formData.append('price', price);
        formData.append('image', image);
        formData.append('category_id', category_id);

        try {
            const response = await axiosClient.post("/books/create", formData, {
                headers: {
                    'Content-Type': 'multipart/form-data'
                }
            });
            setError({});
            window.location.href = "/admin/dashboard/books?message=Book added successfully";
        } catch (error) {
            if (error.response && error.response.status === 422) {
                setError(error.response.data.error || {});
            } else {
                setError({ general: "An unexpected error occurred. Please try again later." });
                console.log(error);
            }
        } finally {
            setLoading(false);
        }
    };

    return (
        <form onSubmit={handleSubmit} className="max-w-2xl mx-auto bg-white dark:bg-midnight-card p-8 rounded-xl shadow-xl dark:shadow-glass-lg border border-slate-200 dark:border-midnight-border transition-colors duration-500">
            <header className="flex justify-between items-center mb-8 pb-6 border-b border-slate-200 dark:border-midnight-border">
                <h2 className="text-3xl font-bold bg-gradient-to-r from-brand-primary to-brand-primary-dark bg-clip-text text-transparent">Add Book</h2>
                <Link to="/admin/dashboard/books" className="p-2 hover:bg-slate-100 dark:hover:bg-midnight-border rounded-full transition-all duration-200 hover:scale-105">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-gray-600 dark:text-slate-400 transition-colors duration-500" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M10.293 2.293a1 1 0 011.414 0l8 8a1 1 0 010 1.414l-8 8a1 1 0 01-1.414-1.414L16.586 11H3a1 1 0 110-2h13.586l-6.293-6.293a1 1 0 010-1.414z" clipRule="evenodd" />
                    </svg>
                </Link>
            </header>

            <div className="space-y-6">
                {loading && (
                    <div className="text-center py-4 bg-white/80 dark:bg-midnight-card/80 rounded-xl backdrop-blur">
                        <div className="inline-block animate-spin rounded-full h-8 w-8 border-b-2 border-brand-primary"></div>
                        <p className="mt-2 text-gray-500 dark:text-slate-400 font-medium">Processing...</p>
                    </div>
                )}

                {error.general && (
                    <div className="bg-red-50 dark:bg-red-950/30 border-l-4 border-red-400 dark:border-red-600 p-4 rounded-md">
                        <p className="text-red-700 dark:text-red-400 text-sm">{error.general}</p>
                    </div>
                )}

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="space-y-2">
                        <label htmlFor="title" className="block text-sm font-medium text-gray-700 dark:text-slate-300 transition-colors duration-500">Title</label>
                    <input
                        type="text"
                        id="title"
                        name="title"
                        value={title}
                        onChange={(e) => setTitle(e.target.value)}
                        className="w-full px-4 py-3 rounded-lg border border-gray-300 dark:border-midnight-border bg-white dark:bg-midnight-800 text-gray-900 dark:text-slate-200 focus:ring-2 focus:ring-brand-primary dark:focus:ring-brand-primary focus:border-transparent transition duration-200"
                        placeholder="Enter book title"
                    />
                        {error.title && <p className="text-red-500 dark:text-red-400 text-xs mt-1">{error.title[0]}</p>}
                </div>

                    <div className="space-y-2">
                        <label htmlFor="author_id" className="block text-sm font-medium text-gray-700 dark:text-slate-300 transition-colors duration-500">Author</label>
                    <select
                        id="author_id"
                        name="author_id"
                        value={author_id}
                        onChange={(e) => setAuthorId(e.target.value)}
                        className="w-full px-4 py-3 rounded-lg border border-gray-300 dark:border-midnight-border bg-white dark:bg-midnight-800 text-gray-900 dark:text-slate-200 focus:ring-2 focus:ring-brand-primary dark:focus:ring-brand-primary focus:border-transparent transition duration-200"
                    >
                        <option value="">Select Author</option>
                            {authors.map(author => (
                            <option key={author.id} value={author.id}>{author.name}</option>
                        ))}
                    </select>
                        {error.author_id && <p className="text-red-500 dark:text-red-400 text-xs mt-1">{error.author_id[0]}</p>}
                    </div>

                    <div className="space-y-2">
                        <label htmlFor="category_id" className="block text-sm font-medium text-gray-700 dark:text-slate-300 transition-colors duration-500">Category</label>
                        <select
                            id="category_id"
                            name="category_id"
                            value={category_id}
                            onChange={(e) => setCategoryId(e.target.value)}
                            className="w-full px-4 py-3 rounded-lg border border-gray-300 dark:border-midnight-border bg-white dark:bg-midnight-800 text-gray-900 dark:text-slate-200 focus:ring-2 focus:ring-brand-primary dark:focus:ring-brand-primary focus:border-transparent transition duration-200"
                        >
                            <option value="">Select Category</option>
                            {categories.map(category => (
                                <option key={category.id} value={category.id}>{category.name}</option>
                            ))}
                        </select>
                        {error.category_id && <p className="text-red-500 dark:text-red-400 text-xs mt-1">{error.category_id[0]}</p>}
                    </div>

                    <div className="space-y-2">
                        <label htmlFor="quantity" className="block text-sm font-medium text-gray-700 dark:text-slate-300 transition-colors duration-500">Quantity</label>
                        <input
                            type="number"
                            id="quantity"
                            name="quantity"
                            value={quantity}
                            onChange={(e) => setQuantity(e.target.value)}
                            className="w-full px-4 py-3 rounded-lg border border-gray-300 dark:border-midnight-border bg-white dark:bg-midnight-800 text-gray-900 dark:text-slate-200 focus:ring-2 focus:ring-brand-primary dark:focus:ring-brand-primary focus:border-transparent transition duration-200"
                            placeholder="Enter quantity"
                        />
                        {error.quantity && <p className="text-red-500 dark:text-red-400 text-xs mt-1">{error.quantity[0]}</p>}
                    </div>
                </div>

                <div className="space-y-2">
                    <label htmlFor="description" className="block text-sm font-medium text-gray-700 dark:text-slate-300 transition-colors duration-500">Description</label>
                    <textarea
                        id="description"
                        name="description"
                        value={description}
                        onChange={(e) => setDescription(e.target.value)}
                        rows="4"
                        className="w-full px-4 py-3 rounded-lg border border-gray-300 dark:border-midnight-border bg-white dark:bg-midnight-800 text-gray-900 dark:text-slate-200 focus:ring-2 focus:ring-brand-primary dark:focus:ring-brand-primary focus:border-transparent transition duration-200"
                        placeholder="Enter book description"
                    />
                    {error.description && <p className="text-red-500 dark:text-red-400 text-xs mt-1">{error.description[0]}</p>}
                </div>

                <div className="space-y-2">
                    <label htmlFor="image" className="block text-sm font-medium text-gray-700 dark:text-slate-300 transition-colors duration-500">Book Cover</label>
                    <div className="mt-1 flex justify-center px-6 pt-5 pb-6 border-2 border-dashed border-gray-300 dark:border-midnight-border rounded-lg hover:border-brand-primary dark:hover:border-brand-primary bg-gray-50 dark:bg-midnight-800/50 transition-colors duration-200">
                        <div className="space-y-1 text-center">
                            <svg className="mx-auto h-12 w-12 text-gray-400 dark:text-slate-500" stroke="currentColor" fill="none" viewBox="0 0 48 48" aria-hidden="true">
                                <path d="M28 8H12a4 4 0 00-4 4v20m32-12v8m0 0v8a4 4 0 01-4 4H12a4 4 0 01-4-4v-4m32-4l-3.172-3.172a4 4 0 00-5.656 0L28 28M8 32l9.172-9.172a4 4 0 015.656 0L28 28m0 0l4 4m4-24h8m-4-4v8m-12 4h.02" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                            </svg>
                            <div className="flex text-sm text-gray-600 dark:text-slate-400">
                                <label htmlFor="image" className="relative cursor-pointer bg-white dark:bg-midnight-card rounded-md font-medium text-brand-primary dark:text-brand-primary hover:text-brand-primary-dark dark:hover:text-brand-light focus-within:outline-none focus-within:ring-2 focus-within:ring-offset-2 focus-within:ring-brand-primary transition-colors duration-300">
                                    <span>Upload a file</span>
                    <input
                        id="image"
                        name="image"
                        type="file"
                        onChange={(e) => setImage(e.target.files[0])}
                        className="sr-only"
                    />
                                </label>
                                <p className="pl-1">or drag and drop</p>
                            </div>
                            <p className="text-xs text-gray-500 dark:text-slate-500">PNG, JPG, GIF up to 10MB</p>
                        </div>
                    </div>
                    {error.image && <p className="text-red-500 dark:text-red-400 text-xs mt-1">{error.image[0]}</p>}
                </div>

                <div className="flex justify-end pt-6">
                    <button
                        type="submit"
                        disabled={loading}
                        className="px-6 py-3 bg-gradient-to-r from-brand-primary to-brand-primary-dark hover:from-brand-primary-dark hover:to-brand-primary text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-offset-2 dark:focus:ring-offset-midnight-card focus:ring-brand-primary transition duration-200 flex items-center space-x-2 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        {loading ? (
                            <>
                                <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-white"></div>
                                <span>Adding Book...</span>
                            </>
                        ) : (
                            <>
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
                                </svg>
                                <span>Add Book</span>
                            </>
                        )}
                    </button>
                </div>
            </div>
        </form>
    );
}

import React, { useState, useRef, useEffect } from 'react';
import './ChatBot.css';
import axiosClient from '../axiosClient';

const ChatBot = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([
    {
      id: 1,
      text: 'Hello! How can I help you today?',
      sender: 'bot',
      timestamp: new Date(),
      liked: false,
    },
  ]);
  const [inputValue, setInputValue] = useState('');
  const [loading, setLoading] = useState(false);
  const [language, setLanguage] = useState('en');
  const [isRTL, setIsRTL] = useState(false);
  const messagesEndRef = useRef(null);

  const handleLikeMessage = (messageId) => {
    setMessages((prev) =>
      prev.map((msg) =>
        msg.id === messageId ? { ...msg, liked: !msg.liked } : msg
      )
    );
  };

  // Scroll to bottom when messages update
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Load user's language preference
  useEffect(() => {
    const loadLanguage = async () => {
      try {
        const response = await axiosClient.get('/chat/context');
        const userLanguage = response.data.context.language || 'en';
        setLanguage(userLanguage);
        setIsRTL(userLanguage === 'ar');
      } catch (error) {
        console.log('Could not load language preference');
      }
    };
    loadLanguage();
  }, []);

  const handleSendMessage = async (e) => {
    e.preventDefault();

    if (!inputValue.trim()) return;

    // Add user message to chat
    const userMessage = {
      id: messages.length + 1,
      text: inputValue,
      sender: 'user',
      timestamp: new Date(),
    };

    setMessages([...messages, userMessage]);
    setInputValue('');
    setLoading(true);

    try {
      const response = await axiosClient.post('/chat/message', {
        message: inputValue,
      });

      const botMessage = {
        id: messages.length + 2,
        text: response.data.response,
        sender: 'bot',
        timestamp: new Date(),
      };

      setMessages((prev) => [...prev, botMessage]);
    } catch (error) {
      console.error('Error sending message:', error);
      const errorMessage = {
        id: messages.length + 2,
        text: 'Sorry, I encountered an error. Please try again.',
        sender: 'bot',
        timestamp: new Date(),
      };
      setMessages((prev) => [...prev, errorMessage]);
    } finally {
      setLoading(false);
    }
  };

  const handleLanguageChange = async (newLanguage) => {
    try {
      await axiosClient.post('/chat/language', {
        language: newLanguage,
      });
      setLanguage(newLanguage);
      setIsRTL(newLanguage === 'ar');
    } catch (error) {
      console.error('Error changing language:', error);
    }
  };

  const getGreeting = () => {
    const greetings = {
      en: 'Library Support',
      ar: 'دعم المكتبة',
      fr: 'Support Bibliothèque',
    };
    return greetings[language] || 'Library Support';
  };

  const getPlaceholder = () => {
    const placeholders = {
      en: 'Type your message...',
      ar: 'اكتب رسالتك...',
      fr: 'Tapez votre message...',
    };
    return placeholders[language] || 'Type your message...';
  };

  const getSendButtonText = () => {
    const texts = {
      en: 'Send',
      ar: 'إرسال',
      fr: 'Envoyer',
    };
    return texts[language] || 'Send';
  };

  return (
    <div className="chatbot-container">
      {/* Floating Button */}
      <button
        className="chatbot-toggle"
        onClick={() => setIsOpen(!isOpen)}
        aria-label="Toggle chatbot"
      >

      </button>

      {/* Chat Window */}
      {isOpen && (
        <div className={`chatbot-window ${isRTL ? 'rtl' : 'ltr'}`} dir={isRTL ? 'rtl' : 'ltr'}>
          {/* Header */}
          <div className="chatbot-header">
            <h3>{getGreeting()}</h3>
            <div className="chatbot-controls">
              <select
                value={language}
                onChange={(e) => handleLanguageChange(e.target.value)}
                className="language-selector"
              >
                <option value="en">English</option>
                <option value="ar">العربية</option>
                <option value="fr">Français</option>
              </select>
              <button
                className="close-button"
                onClick={() => setIsOpen(false)}
                aria-label="Close chatbot"
              >
                ✕
              </button>
            </div>
          </div>

          {/* Messages Container */}
          <div className="chatbot-messages">
            {messages.map((msg) => (
              <div
                key={msg.id}
                className={`message ${msg.sender === 'user' ? 'user-message' : 'bot-message'}`}
              >
                {msg.sender === 'bot' && (
                  <button
                    className={`like-button ${msg.liked ? 'liked' : ''}`}
                    onClick={() => handleLikeMessage(msg.id)}
                    aria-label="Like this message"
                    title={msg.liked ? 'Unlike' : 'Like'}
                  >
                    {msg.liked ? '❤️' : ''}
                  </button>
                )}
                <p>{msg.text}</p>
              </div>
            ))}
            {loading && (
              <div className="message bot-message">
                <p className="typing-indicator">
                  <span></span>
                  <span></span>
                  <span></span>
                </p>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input Form */}
          <form className="chatbot-input-form" onSubmit={handleSendMessage}>
            <input
              type="text"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={getPlaceholder()}
              disabled={loading}
              className="chatbot-input"
            />
            <button
              type="submit"
              disabled={loading || !inputValue.trim()}
              className="send-button"
            >
              {getSendButtonText()}
            </button>
          </form>
        </div>
      )}
    </div>
  );
};

export default ChatBot;

import React, { useState, useRef, useEffect } from 'react';
import './ChatBot.css';
import axiosClient from '../axiosClient';

const ChatBot = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([
    {
      id: 1,
      text: 'Hello! How can I help you today?',
      sender: 'bot',
      timestamp: new Date(),
      liked: false,
    },
  ]);
  const [inputValue, setInputValue] = useState('');
  const [loading, setLoading] = useState(false);
  const [language, setLanguage] = useState('en');
  const [isRTL, setIsRTL] = useState(false);
  const messagesEndRef = useRef(null);

  const handleLikeMessage = (messageId) => {
    setMessages((prev) =>
      prev.map((msg) =>
        msg.id === messageId ? { ...msg, liked: !msg.liked } : msg
      )
    );
  };

  // Scroll to bottom when messages update
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Load user's language preference
  useEffect(() => {
    const loadLanguage = async () => {
      try {
        const response = await axiosClient.get('/chat/context');
        const userLanguage = response.data.context.language || 'en';
        setLanguage(userLanguage);
        setIsRTL(userLanguage === 'ar');
      } catch (error) {
        console.log('Could not load language preference');
      }
    };
    loadLanguage();
  }, []);

  const handleSendMessage = async (e) => {
    e.preventDefault();

    if (!inputValue.trim()) return;

    // Add user message to chat
    const userMessage = {
      id: messages.length + 1,
      text: inputValue,
      sender: 'user',
      timestamp: new Date(),
    };

    setMessages([...messages, userMessage]);
    setInputValue('');
    setLoading(true);

    try {
      const response = await axiosClient.post('/chat/message', {
        message: inputValue,
      });

      const botMessage = {
        id: messages.length + 2,
        text: response.data.response,
        sender: 'bot',
        timestamp: new Date(),
        liked: false,
      };

      setMessages((prev) => [...prev, botMessage]);
    } catch (error) {
      console.error('Error sending message:', error);
      const errorMessage = {
        id: messages.length + 2,
        text: 'Sorry, I encountered an error. Please try again.',
        sender: 'bot',
        timestamp: new Date(),
      };
      setMessages((prev) => [...prev, errorMessage]);
    } finally {
      setLoading(false);
    }
  };

  const handleLanguageChange = async (newLanguage) => {
    try {
      await axiosClient.post('/chat/language', {
        language: newLanguage,
      });
      setLanguage(newLanguage);
      setIsRTL(newLanguage === 'ar');
    } catch (error) {
      console.error('Error changing language:', error);
    }
  };

  const getGreeting = () => {
    const greetings = {
      en: 'Library Support',
      ar: 'دعم المكتبة',
      fr: 'Support Bibliothèque',
    };
    return greetings[language] || 'Library Support';
  };

  const getPlaceholder = () => {
    const placeholders = {
      en: 'Type your message...',
      ar: 'اكتب رسالتك...',
      fr: 'Tapez votre message...',
    };
    return placeholders[language] || 'Type your message...';
  };

  const getSendButtonText = () => {
    const texts = {
      en: 'Send',
      ar: 'إرسال',
      fr: 'Envoyer',
    };
    return texts[language] || 'Send';
  };

  return (
    <div className="chatbot-container">
      {/* Floating Button */}
      <button
        className="chatbot-toggle"
        onClick={() => setIsOpen(!isOpen)}
        aria-label="Toggle chatbot"
      >

      </button>

      {/* Chat Window */}
      {isOpen && (
        <div className={`chatbot-window ${isRTL ? 'rtl' : 'ltr'}`} dir={isRTL ? 'rtl' : 'ltr'}>
          {/* Header */}
          <div className="chatbot-header">
            <h3>{getGreeting()}</h3>
            <div className="chatbot-controls">
              <select
                value={language}
                onChange={(e) => handleLanguageChange(e.target.value)}
                className="language-selector"
              >
                <option value="en">English</option>
                <option value="ar">العربية</option>
                <option value="fr">Français</option>
              </select>
              <button
                className="close-button"
                onClick={() => setIsOpen(false)}
                aria-label="Close chatbot"
              >
                ✕
              </button>
            </div>
          </div>

          {/* Messages Container */}
          <div className="chatbot-messages">
            {messages.map((msg) => (
              <div
                key={msg.id}
                className={`message ${msg.sender === 'user' ? 'user-message' : 'bot-message'}`}
              >
                {msg.sender === 'bot' && (
                  <button
                    className={`like-button ${msg.liked ? 'liked' : ''}`}
                    onClick={() => handleLikeMessage(msg.id)}
                    aria-label="Like this message"
                    title={msg.liked ? 'Unlike' : 'Like'}
                  >
                    {msg.liked ? '❤️' : ''}
                  </button>
                )}
                <p>{msg.text}</p>
              </div>
            ))}
            {loading && (
              <div className="message bot-message">
                <p className="typing-indicator">
                  <span></span>
                  <span></span>
                  <span></span>
                </p>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input Form */}
          <form className="chatbot-input-form" onSubmit={handleSendMessage}>
            <input
              type="text"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={getPlaceholder()}
              disabled={loading}
              className="chatbot-input"
            />
            <button
              type="submit"
              disabled={loading || !inputValue.trim()}
              className="send-button"
            >
              {getSendButtonText()}
            </button>
          </form>
        </div>
      )}
    </div>
  );
};

export default ChatBot;

import React, { useState, useEffect } from "react";
import axiosClient from "../../../axiosClient";
import { Link, useNavigate } from "react-router-dom";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import { faTrash } from "@fortawesome/free-solid-svg-icons";
import { useUser } from "../../../context/UserContext";
import { format } from "date-fns";

function BorrowRecordCard({ borrowRecord }) {
  const { book } = borrowRecord;
  const isReturned = borrowRecord.return_date !== null;

  const formatDate = (date) => {
    return format(new Date(date), "dd/MM/yy");
  };

  return (
    <div className="bg-white dark:bg-slate-700 rounded-xl overflow-hidden shadow-lg hover:shadow-xl transition-shadow duration-300 ease-in-out">
      <div className="relative">
      <img
          src={`http://localhost:8000/storage/${book.image}`}
          alt={book.title}
          className="h-64 w-full object-cover transform hover:scale-105 transition-transform duration-300"
      />
        <div className="absolute bottom-0 left-0 right-0 bg-gradient-to-t from-black/70 to-transparent p-4">
          <h2 className="text-xl font-bold text-white truncate">{book.title}</h2>
          <p className="text-white/90 text-sm">{book.author ? book.author.name : ''}</p>
        </div>
      </div>

      <div className="p-5">
        <div className="flex items-center justify-between mb-4">
          <span className={`px-3 py-1 rounded-full text-sm font-medium ${
            isReturned 
            ? 'bg-green-100 dark:bg-green-900/30 text-green-800 dark:text-green-200' 
            : 'bg-yellow-100 dark:bg-yellow-900/30 text-yellow-800 dark:text-yellow-200'
          }`}>
            {isReturned ? 'Returned' : 'Not Returned'}
          </span>
          <span className="text-sm text-gray-600 dark:text-gray-300">
            {isReturned 
              ? `Returned: ${formatDate(borrowRecord.return_date)}`
              : `Due: ${formatDate(borrowRecord.due_date)}`
            }
          </span>
        </div>

        <div className="space-y-2">
          <div className="flex items-center text-gray-600 dark:text-gray-300">
            <span className="text-sm font-medium w-24">Category:</span>
            <span className="text-sm">{book.category ? book.category.name : '-'}</span>
          </div>
          <div className="flex items-center text-gray-600 dark:text-gray-300">
            <span className="text-sm font-medium w-24">Borrowed:</span>
            <span className="text-sm">{formatDate(borrowRecord.borrow_date)}</span>
          </div>
          <div className="mt-3">
            <p className="text-sm text-gray-600 dark:text-gray-300 line-clamp-2">
              {book.description}
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

export function HistoryTable() {
  const { user } = useUser();
  const [borrowRecords, setBorrowRecords] = useState([]);
  const [loading, setLoading] = useState(false);
  const [successMessage, setSuccessMessage] = useState(null);
  const [page, setPage] = useState(1);
  const [perPage, setPerPage] = useState(10);
  const [searchTerm, setSearchTerm] = useState("");
  const [filteredBorrowRecords, setFilteredBorrowRecords] = useState([]);

  useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const message = urlParams.get("message");
    if (message) {
      setSuccessMessage(message);
    }
  }, []);

  useEffect(() => {
    if (!user) return;
    setLoading(true);
    axiosClient
      .get(`/borrow-records/user/${user.id}/history`)
      .then((response) => {
        setBorrowRecords(response.data);
        setFilteredBorrowRecords(response.data);
        setLoading(false);
      })
      .catch((error) => {
        console.error("Error fetching borrow records:", error);
        setLoading(false);
      });
  }, [user.id]);

  useEffect(() => {
    const filtered = borrowRecords.filter((borrowRecord) => {
      const searchString = searchTerm.toLowerCase();
      return (
        (borrowRecord.book?.title || '').toLowerCase().includes(searchString) ||
        (borrowRecord.book?.description || '').toLowerCase().includes(searchString) ||
        (borrowRecord.book?.author?.name || '').toLowerCase().includes(searchString) ||
        (borrowRecord.book?.category?.name || '').toLowerCase().includes(searchString) ||
        (borrowRecord.borrow_date || '').toLowerCase().includes(searchString) ||
        (borrowRecord.return_date || '').toLowerCase().includes(searchString)
      );
    });

    setFilteredBorrowRecords(filtered);
  }, [searchTerm, borrowRecords]);

  const handleSearch = (e) => {
    setSearchTerm(e.target.value);
  };

  const paginatedBorrowRecords = filteredBorrowRecords.slice((page - 1) * perPage, page * perPage);
  const totalPages = Math.ceil(filteredBorrowRecords.length / perPage);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div
          className="spinner-border animate-spin inline-block w-8 h-8 border-b-2 border-blue-500 rounded-full"
          role="status"
        >
          <span className="visually-hidden">Loading...</span>
        </div>
      </div>
    );
  }
  return (
    <div className="container mx-auto px-4">
      {successMessage && (
        <div className="p-4 mb-4 text-green-700 dark:text-green-200 bg-green-100 dark:bg-green-900/30 rounded-lg" role="alert">
          <p>{successMessage}</p>
        </div>
      )}
      <div className="flex justify-between items-center py-4">
        <h2 className="text-2xl font-semibold text-slate-900 dark:text-white">History</h2>
      </div>
      <div className="flex items-center justify-between py-4">
        <div className="space-x-2">
          <input
            type="text"
            value={searchTerm}
            onChange={handleSearch}
            className="py-2 px-4 border border-gray-300 dark:border-slate-600 rounded-md shadow-sm bg-white dark:bg-slate-700 text-slate-900 dark:text-white"
            placeholder="Search..."
          />
        </div>
        <div className="space-x-2">
          <span className="text-sm text-slate-700 dark:text-slate-300">Show</span>
          <select
            value={perPage}
            onChange={(e) => setPerPage(parseInt(e.target.value))}
            className="py-2 px-4 border border-gray-300 dark:border-slate-600 rounded-md shadow-sm bg-white dark:bg-slate-700 text-slate-900 dark:text-white"
          >
            <option value="5">5</option>
            <option value="10">10</option>
            <option value="15">15</option>
            <option value="20">20</option>
          </select>
        </div>
        <div className="space-x-2">
          <button
            onClick={() => setPage(page - 1)}
            className="py-2 px-4 border border-gray-300 dark:border-slate-600 rounded-md shadow-sm bg-white dark:bg-slate-700 hover:bg-gray-50 dark:hover:bg-slate-600 disabled:opacity-50 text-slate-900 dark:text-white"
            disabled={page === 1}
          >
            Previous
          </button>
          <span className="text-sm text-slate-700 dark:text-slate-300">
            Page {page} of {totalPages}
          </span>
          <button
            onClick={() => setPage(page + 1)}
            className="py-2 px-4 border border-gray-300 dark:border-slate-600 rounded-md shadow-sm bg-white dark:bg-slate-700 hover:bg-gray-50 dark:hover:bg-slate-600 disabled:opacity-50 text-slate-900 dark:text-white"
            disabled={page === totalPages}
          >
            Next
          </button>
        </div>
      </div>
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
        {paginatedBorrowRecords.map((borrowRecord, index) => (
          <BorrowRecordCard key={borrowRecord.id} borrowRecord={borrowRecord} />
        ))}
      </div>
    </div>
  );
}

